import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.PsiComment

internal class KtlintSuppressionRule :
    Rule(
        ruleId = KTLINT_SUPPRESSION_RULE_ID,
        about = About(
            maintainer = "KtLint",
            repositoryUrl = "https://github.com/pinterest/ktlint",
            issueTrackerUrl = "https://github.com/pinterest/ktlint/issues",
        ),
    ),
    InternalRule {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.psi is PsiComment) {
            val text = node.text
            if (KTLINT_SUPPRESSION_DIRECTIVE_REGEXP.containsMatchIn(text)) {
                emit(
                    node.startOffset,
                    "Directives 'ktlint-disable' and 'ktlint-enable' are deprecated. Use '@Suppress' annotation instead.",
                    false,
                )
            }
        }
    }

    companion object {
        val KTLINT_SUPPRESSION_RULE_ID = RuleId("ktlint:suppression")
        private val KTLINT_SUPPRESSION_DIRECTIVE_REGEXP = Regex("ktlint-(disable|enable)")
    }
}
