import com.pinterest.ktlint.rule.engine.api.Code
import com.pinterest.ktlint.rule.engine.api.KtLintRuleEngine
import com.pinterest.ktlint.rule.engine.api.LintError
import com.pinterest.ktlint.rule.engine.core.api.ElementType
import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import org.assertj.core.api.Assertions.assertThat
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.junit.jupiter.api.Test

class KtlintSuppressionRuleTest {
    @Test
    fun `Given that a NoFooIdentifierRule violation is suppressed with an EOL-comment then find a violation for the directive and the rule`() {
        val code =
            """
            val foo = "foo" // ktlint-disable
            """.trimIndent()
        assertThat(lint(code)).containsExactly(
            LintError(1, 5, RuleId("standard:no-foo-identifier"), "Line should not contain a foo identifier", false),
            LintError(1, 17, RuleId("ktlint:suppression"), "Directives 'ktlint-disable' and 'ktlint-enable' are deprecated. Use '@Suppress' annotation instead.", false),
        )
    }

    @Test
    fun `Given that a NoFooIdentifierRule violation is suppressed with a block comment then find a violation for the directive and the rule`() {
        val code =
            """
            /* ktlint-disable */
            val foo = "foo"
            /* ktlint-enable */
            """.trimIndent()
        assertThat(lint(code)).containsExactly(
            LintError(1, 1, RuleId("ktlint:suppression"), "Directives 'ktlint-disable' and 'ktlint-enable' are deprecated. Use '@Suppress' annotation instead.", false),
            LintError(2, 5, RuleId("standard:no-foo-identifier"), "Line should not contain a foo identifier", false),
            LintError(3, 1, RuleId("ktlint:suppression"), "Directives 'ktlint-disable' and 'ktlint-enable' are deprecated. Use '@Suppress' annotation instead.", false),
        )
    }

    @Test
    fun `Given that a NoFooIdentifierRule violation is suppressed with an experimental rule id then find a violation for the directive and the rule`() {
        val code =
            """
            val foo = "foo" // ktlint-disable experimental:no-foo-identifier
            """.trimIndent()
        assertThat(lint(code)).containsExactly(
            LintError(1, 5, RuleId("standard:no-foo-identifier"), "Line should not contain a foo identifier", false),
            LintError(1, 17, RuleId("ktlint:suppression"), "Directives 'ktlint-disable' and 'ktlint-enable' are deprecated. Use '@Suppress' annotation instead. Experimental rules are now standard rules.", false),
        )
    }

    private class NoFooIdentifierRule : Rule(
        ruleId = RuleId("standard:no-foo-identifier"),
        about = About(),
    ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
            if (node.elementType == ElementType.IDENTIFIER && node.text.startsWith("foo")) {
                emit(node.startOffset, "Line should not contain a foo identifier", false)
            }
        }
    }

    private fun lint(code: String) = ArrayList<LintError>().apply {
        KtLintRuleEngine(
            ruleProviders = setOf(
                RuleProvider { NoFooIdentifierRule() }
            )
        ).lint(Code.fromSnippet(code)) { e -> add(e) }
    }
}
